import { motion } from "framer-motion";

export default function LayeredMilestoneCard() {
  return (() => <div style={{display:"grid",placeItems:"center",height:"100%",minHeight:250,background:"#f4f5f6",borderRadius:20}}><motion.article initial="rest" whileHover="open" whileFocus="open" tabIndex={0} style={{position:"relative",width:285,height:175}}>{[["APR 12","Scope"],["MAY 08","Build"],["JUN 21","Launch"]].map(([date,label],i)=><motion.div key={date} variants={{rest:{x:i*6,y:i*7,rotate:0},open:{x:(i-1)*24,y:-i*14,rotate:(i-1)*3}}} transition={{type:"spring",stiffness:280,damping:26,delay:i*.05}} style={{position:"absolute",inset:0,padding:18,borderRadius:22,background:"#fff",border:"1px solid #ececee",fontFamily:"Inter, sans-serif"}}><small>{date}</small><strong style={{display:"block",marginTop:62,fontSize:24}}>{label}</strong><span style={{display:"block",width:(i+1)*25+"%",height:7,background:i===2?"#ff9950":"#53e8d4"}}/></motion.div>)}</motion.article></div>)();
